To render a 3D model of a house, the best approach for a web-based solution is using **Three.js**. It is a powerful JavaScript library that allows us to create 3D graphics in the browser using WebGL.

Below is a complete, single-file solution. It procedurally generates a simple house (a cube for the body and a pyramid for the roof) so you don't need to download external 3D files.

### How to use this:
1.  Create a new file on your computer named `house.html`.
2.  Paste the code below into that file.
3.  Open `house.html` in any modern web browser (Chrome, Firefox, Edge).

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from a CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. SCENE SETUP
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(5, 5, 8);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // 2. CONTROLS (Mouse interaction)
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // 3. LIGHTING
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. MATERIALS
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 }); // Brown roof
        const glassMaterial = new THREE.MeshStandardMaterial({ color: 0x88ccff, transparent: true, opacity: 0.6 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. BUILDING THE HOUSE
        const houseGroup = new THREE.Group();

        // --- The Body (Cube) ---
        const bodyGeometry = new THREE.BoxGeometry(2, 2, 2);
        const body = new THREE.Mesh(bodyGeometry, wallMaterial);
        body.position.y = 1; // Sit on the ground
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // --- The Roof (Pyramid) ---
        const roofGeometry = new THREE.ConeGeometry(2, 1.5, 4); // 4 segments for a square pyramid
        const roof = new THREE.Mesh(roofGeometry, roofMaterial);
        roof.position.y = 2.5; // Sit on top of the body
        roof.rotation.y = Math.PI / 4; // Rotate to align with the square base
        roof.castShadow = true;
        roof.receiveShadow = true;
        houseGroup.add(roof);

        // --- The Door ---
        const doorGeometry = new THREE.BoxGeometry(0.8, 1.2, 0.1);
        const door = new THREE.Mesh(doorGeometry, new THREE.MeshStandardMaterial({ color: 0x5c4033 }));
        door.position.set(0, 0.6, 1.01); // Slightly in front of the wall
        houseGroup.add(door);

        // --- The Window ---
        const windowGeometry = new THREE.BoxGeometry(0.6, 0.6, 0.05);
        const windowMesh = new THREE.Mesh(windowGeometry, glassMaterial);
        windowMesh.position.set(0, 1.2, 1.03);
        houseGroup.add(windowMesh);

        // --- The Ground (Grass) ---
        const groundGeometry = new THREE.PlaneGeometry(50, 50);
        const ground = new THREE.Mesh(groundGeometry, grassMaterial);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        scene.add(houseGroup);

        // 6. ANIMATION LOOP
        function animate() {
            requestAnimationFrame(animate);
            controls.update(); // Required for damping
            renderer.render(scene, camera);
        }

        // Handle window resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### Key Features of this Code:
1.  **Procedural Generation:** It builds the house using geometric primitives (Box, Cone) rather than loading an external `.obj` or `.gltf` file. This ensures the code runs instantly without CORS errors or missing file dependencies.
2.  **Lighting & Shadows:** It uses a `DirectionalLight` to simulate the sun, casting realistic shadows on the ground and the house itself.
3.  **Interactivity:** It includes `OrbitControls`, allowing you to click and drag to rotate around the house and scroll to zoom in/out.
4.  **Responsive:** The canvas automatically resizes if you change the browser window size.
